/**
 * Creating a sidebar enables you to:
  - create an ordered group of docs
  - render a sidebar for each doc of that group
  - provide next/previous navigation
  The sidebars can be generated from the filesystem, or explicitly defined here.
  Create as many sidebars as you want.
 */

// @ts-check

/**
 * One scoped sidebar per section, each autogenerated from inside its own
 * folder. Because every doc belongs to exactly one sidebar, selecting a
 * top-bar item shows ONLY that section's links — the rest collapse away.
 * `concepts` and `learn` are the site-level Explanation / Tutorial homes
 * of the hybrid Diátaxis IA.
 */

/** @type {import('@docusaurus/plugin-content-docs').SidebarsConfig} */
const sidebars = {
  state: [{ type: 'autogenerated', dirName: 'packages/state' }],
  template: [{ type: 'autogenerated', dirName: 'packages/template' }],
  cdk: [{ type: 'autogenerated', dirName: 'packages/cdk' }],
  isr: [{ type: 'autogenerated', dirName: 'packages/isr' }],
  eslintPlugin: [{ type: 'autogenerated', dirName: 'packages/eslint-plugin' }],
  learn: [
    {
      type: 'category',
      label: 'Learn',
      link: { type: 'generated-index', slug: '/tutorials' },
      items: [{ type: 'autogenerated', dirName: 'tutorials' }],
    },
  ],
  concepts: [
    {
      type: 'category',
      label: 'Concepts',
      link: { type: 'generated-index', slug: '/concepts' },
      items: [{ type: 'autogenerated', dirName: 'concepts' }],
    },
  ],
  startHere: [{ type: 'autogenerated', dirName: 'start-here' }],
};

module.exports = sidebars;
